FUNCTION_REPLACEMENTS = json.loads("{\"features/product_ui.py\": {\"render_specialist_sidebar\": \"\"}, \"features/overview_v3.py\": {\"_go_to_market\": \"\", \"render_stage_explorer\": \"...<snip>\"}, \"features/tournament_path_page.py\": {\"_render_country_page_v2\": \"...<snip>\"}}")
