def decode(value: str) -> str:
    return base64.b64decode(value.encode("ascii")).decode("utf-8")


def read(path: str) -> str:
    return (ROOT / path).read_text(encoding="utf-8")


def write(path: str, content: str) -> None:
    target = ROOT / path
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content.rstrip() + "\n", encoding="utf-8")


def replace_function(text: str, name: str, replacement: str) -> str:
    pattern = re.compile(
        rf"^def {re.escape(name)}\(.*?(?=^def |\Z)",
        flags=re.MULTILINE | re.DOTALL,
    )
    updated, count = pattern.subn(replacement.rstrip() + "\n\n", text, count=1)
    if count != 1:
        raise RuntimeError(f"Could not replace function {name}; found {count}.")
    return updated


def apply_full_writes() -> None:
    for path, encoded in FULL_WRITES.items():
        write(path, decode(encoded))


def apply_function_replacements() -> None:
    for path, functions in FUNCTION_REPLACEMENTS.items():
        text = read(path)
        for name, encoded in functions.items():
            text = replace_function(text, name, decode(encoded))
        write(path, text)


def apply_text_replacements() -> None:
    for path, replacements in TEXT_REPLACEMENTS.items():
        text = read(path)
        for old_encoded, new_encoded in replacements:
            old = decode(old_encoded)
            new = decode(new_encoded)
            count = text.count(old)
            if count != 1:
                raise RuntimeError(
                    f"Expected one text replacement in {path}; found {count} for {old[:80]!r}."
                )
            text = text.replace(old, new, 1)
        write(path, text)


def main() -> None:
    apply_full_writes()
    apply_function_replacements()
    apply_text_replacements()
    print("CupMarket UX writing and information architecture refresh applied.")


if __name__ == "__main__":
    main()
